//! Emit `crates/thetadatadx/src/tdbe/types/generated/tick.rs` -- the
//! `#[repr(C, align(N))]` struct definitions for every tick type declared
//! in `tick_schema.toml`.
//!
//! The hand-written `crates/thetadatadx/src/tdbe/types/tick.rs` keeps the
//! items the schema cannot (yet) express: the `impl_contract_id!` macro
//! applications, custom `impl TradeTick { ... }` flag helpers, and
//! `OptionContract`'s deep-copy methods. It `pub use`s the structs from
//! this generated file so every `Vec<T>` consumer in the workspace picks
//! up new tick types automatically.
//!
//! Layout decisions (alignment, copy-derive, contract-id field tail,
//! `QuoteTick.midpoint`) are taken straight from the schema:
//!
//! * `align = N` -> `#[repr(C, align(N))]` (omitted for no align).
//! * `copy = true/false` -> `#[derive(Clone, Copy)]` vs `#[derive(Clone)]`.
//! * `contract_id = true` -> append `expiration: i32`, `strike: f64`,
//!   `right: i32` after the schema columns.
//! * `QuoteTick` -> append `midpoint: f64`. The parser computes it from
//!   `(bid + ask) / 2.0`; the field exists on the struct so consumers
//!   don't recompute.

use std::fmt::Write as _;

use super::idents::rust_field_ident;
use super::layout::{tick_ffi_offsets, tick_ffi_size_and_align};
use super::schema::{Schema, TickTypeDef};
use super::sorted_type_names;

pub(super) fn render_tdbe_tick_structs(schema: &Schema) -> String {
    let mut out = String::new();
    out.push_str(
        "// @generated DO NOT EDIT -- regenerated by\n\
         // `cargo run -p thetadatadx --bin generate_sdk_surfaces`\n\
         // from `crates/thetadatadx/tick_schema.toml`.\n\
         //\n\
         // Per-tick `#[repr(C, align(N))]` struct definitions. The\n\
         // hand-written `tick.rs` `pub use`s every type from this file,\n\
         // adds the `impl_contract_id!` macro applications + custom\n\
         // `Display` / `OptionContract` impls, then re-exports through\n\
         // `tdbe::types::tick`.\n\n",
    );

    for type_name in sorted_type_names(schema) {
        let def = &schema.types[type_name];
        out.push_str(&render_one_struct(type_name, def));
        out.push('\n');
        out.push_str(&render_timestamp_accessors(type_name, def));
    }

    out
}

/// Emit `*_timestamp_ms()` convenience accessors for every tick type
/// that carries both a `date` column and one or more milliseconds-of-day
/// columns. The bare `ms_of_day` field yields `timestamp_ms()`; a
/// prefixed `<x>_ms_of_day` field yields `<x>_timestamp_ms()` (so
/// `EodTick` gets `created_timestamp_ms()` / `last_trade_timestamp_ms()`
/// and the Greeks rows get `underlying_timestamp_ms()`).
///
/// The raw integer fields stay primary — per the workspace raw-ms
/// doctrine the accessors are read-side conveniences at the epoch
/// boundary, computed on demand and never stored.
fn render_timestamp_accessors(type_name: &str, def: &TickTypeDef) -> String {
    let ms_fields = timestamp_accessor_fields(def);
    if ms_fields.is_empty() {
        return String::new();
    }
    let mut out = String::new();
    writeln!(out, "impl {type_name} {{").unwrap();
    for (accessor, field) in &ms_fields {
        writeln!(
            out,
            "    /// Unix epoch milliseconds (UTC, DST-aware) combining `date`\n\
             \x20   /// with `{field}` (Eastern-Time milliseconds-of-day). Returns\n\
             \x20   /// `None` when `date` is absent (`0`) or `{field}` is outside\n\
             \x20   /// the milliseconds-of-day domain. The raw integer fields stay\n\
             \x20   /// primary; this accessor is a convenience at the epoch boundary.\n\
             \x20   #[must_use]\n\
             \x20   pub fn {accessor}(&self) -> Option<i64> {{\n\
             \x20       crate::tdbe::time::date_ms_to_epoch_ms(self.date, self.{field})\n\
             \x20   }}"
        )
        .unwrap();
    }
    out.push_str("}\n\n");
    out
}

/// `(accessor_name, ms_field)` pairs for [`render_timestamp_accessors`].
/// Shared with the Python pyclass emitter so both bindings surface the
/// same accessor set. Empty when the type has no `date` column.
pub(super) fn timestamp_accessor_fields(def: &TickTypeDef) -> Vec<(String, String)> {
    if !def.columns.iter().any(|c| c.field == "date") {
        return Vec::new();
    }
    let mut out = Vec::new();
    for column in &def.columns {
        if column.field == "ms_of_day" {
            out.push(("timestamp_ms".to_string(), column.field.clone()));
        } else if let Some(prefix) = column.field.strip_suffix("_ms_of_day") {
            out.push((format!("{prefix}_timestamp_ms"), column.field.clone()));
        }
    }
    out
}

/// Emit `crates/thetadatadx/src/tdbe/types/generated/tick_layout_asserts.rs`
/// -- a `#[cfg(test)]` module containing `size_of` / `align_of` / `offset_of!`
/// asserts for every tick struct in the schema. The hand-written
/// `tick.rs` `include!`s it.
///
/// Each tick type emits one `#[test] fn <type>_layout()` that pins:
///   * total `size_of::<T>()`     (catches tail-padding drift),
///   * `align_of::<T>()`          (catches `align(N)` drift),
///   * `offset_of!(T, field)`     for every column the parser fills, plus
///     the `contract_id` triple and `QuoteTick.midpoint` tail. This is the
///     ABI that the C-mirror in `sdks/cpp/include/thetadx.h` and the
///     layout-assert `*.hpp.inc` all index into via `offsetof()`.
///
/// `OptionContract` is skipped: its FFI mirror carries a `*const c_char`
/// pointer (`String` schema column) so it never crosses the C ABI as a
/// plain `#[repr(C)]` array element.
pub(super) fn render_tdbe_layout_asserts(schema: &Schema) -> String {
    let mut out = String::new();
    out.push_str(
        "// @generated DO NOT EDIT -- regenerated by\n\
         // `cargo run -p thetadatadx --bin generate_sdk_surfaces`\n\
         // from `crates/thetadatadx/tick_schema.toml`.\n\
         //\n\
         // Per-tick `size_of` / `align_of` / `offset_of!` asserts. Pinned\n\
         // against the Go FFI offset table emitted from the same schema, so\n\
         // any drift between Rust struct layout and the C / Go FFI mirrors\n\
         // surfaces on `cargo test -p thetadatadx` before it lands on the FFI side.\n\
         \n\
         #[cfg(test)]\n\
         mod layout_asserts {\n\
         \x20   use super::*;\n\
         \x20   use std::mem::{align_of, offset_of, size_of};\n\n",
    );

    for type_name in sorted_type_names(schema) {
        if type_name == "OptionContract" {
            // OptionContract carries a heap-allocated root string; the C
            // mirror is hand-written (TdxOptionContract) and the FFI never
            // ships an `OptionContract` array as a `#[repr(C)]` slice over
            // the boundary. Layout asserts therefore only cover columnar
            // tick structs.
            continue;
        }
        let def = &schema.types[type_name];
        let (size, align) = tick_ffi_size_and_align(type_name, def);
        let snake = pascal_to_snake(type_name);

        writeln!(out, "    #[test]").unwrap();
        writeln!(out, "    fn {snake}_layout() {{").unwrap();
        writeln!(out, "        assert_eq!(size_of::<{type_name}>(), {size});").unwrap();
        writeln!(
            out,
            "        assert_eq!(align_of::<{type_name}>(), {align});"
        )
        .unwrap();
        for (field, offset) in tick_ffi_offsets(type_name, def) {
            let field = rust_field_ident(&field);
            writeln!(
                out,
                "        assert_eq!(offset_of!({type_name}, {field}), {offset});"
            )
            .unwrap();
        }
        out.push_str("    }\n\n");
    }

    out.push_str("}\n");
    out
}

/// Convert a PascalCase tick type name (`GreeksFirstOrderTick`) to the
/// snake_case form used in test names (`greeks_first_order_tick`). Pure
/// helper -- not exported.
fn pascal_to_snake(name: &str) -> String {
    let mut out = String::new();
    for (i, ch) in name.chars().enumerate() {
        if ch.is_ascii_uppercase() {
            if i != 0 {
                out.push('_');
            }
            out.push(ch.to_ascii_lowercase());
        } else {
            out.push(ch);
        }
    }
    out
}

fn render_one_struct(type_name: &str, def: &TickTypeDef) -> String {
    let mut out = String::new();

    // Doc comment lifted verbatim from the schema. Multi-line docs
    // (e.g. `GreeksTick`) preserve their per-line `///` shape.
    let doc = if def.doc.is_empty() {
        format!("`{type_name}` tick.")
    } else {
        def.doc.clone()
    };
    for line in doc.lines() {
        if line.is_empty() {
            out.push_str("///\n");
        } else {
            writeln!(out, "/// {line}").unwrap();
        }
    }

    out.push_str("#[must_use]\n");
    if def.copy {
        out.push_str("#[derive(Debug, Clone, Copy)]\n");
    } else {
        out.push_str("#[derive(Debug, Clone)]\n");
    }
    if let Some(align) = def.align {
        writeln!(out, "#[repr(C, align({align}))]").unwrap();
    } else {
        out.push_str("#[repr(C)]\n");
    }
    writeln!(out, "pub struct {type_name} {{").unwrap();

    for column in &def.columns {
        let rust_ty = struct_field_rust_type(column.r#type.as_str(), type_name, &column.field);
        if let Some(doc) = &column.doc {
            for line in doc.lines() {
                if !line.is_empty() {
                    writeln!(out, "    /// {line}").unwrap();
                }
            }
        }
        writeln!(
            out,
            "    pub {}: {rust_ty},",
            rust_field_ident(&column.field)
        )
        .unwrap();
    }

    // Field order MUST match the legacy `tick.rs` layout for FFI ABI
    // compatibility: `contract_id` triple comes BEFORE `QuoteTick.midpoint`.
    // Reordering would silently shift offsets for already-compiled C / C++ /
    // Go consumers even when total `size_of` stays the same.
    if def.contract_id {
        out.push_str("    /// Contract expiration (`YYYYMMDD`). Populated on wildcard queries, 0 otherwise.\n");
        out.push_str("    pub expiration: i32,\n");
        out.push_str("    /// Contract strike price in dollars. Populated on wildcard queries, 0.0 otherwise.\n");
        out.push_str("    pub strike: f64,\n");
        out.push_str("    /// Contract right: `'C'` for a call, `'P'` for a put. `'\\0'` on single-contract queries.\n");
        out.push_str("    pub right: char,\n");
    }

    if type_name == "QuoteTick" {
        out.push_str("    /// Pre-computed midpoint: `(bid + ask) / 2.0`.\n");
        out.push_str("    pub midpoint: f64,\n");
    }

    out.push_str("}\n");
    out
}

/// Map a schema column type to the Rust field type used in the generated
/// `tdbe::types::tick` struct. Mirrors the parser emitter in
/// `build_support/ticks/parser.rs` -- every `eod_*` and `price` column
/// is decoded to its widened Rust type at parse time, so the struct
/// field type matches the parser's terminal type. Logical columns map
/// to their typed Rust forms: `right` -> `char` (4-byte Unicode scalar,
/// same layout slot as the wire's i32), `bool` -> `bool`,
/// `calendar_status` -> the exported `CalendarStatus` enum
/// (`repr(i32)`).
fn struct_field_rust_type(column_type: &str, type_name: &str, field: &str) -> &'static str {
    match column_type {
        "i32" | "eod_num" | "eod_date" => "i32",
        "i64" | "eod_num64" => "i64",
        "f64" | "price" | "eod_price" => "f64",
        "String" => "String",
        "right" => "char",
        "bool" => "bool",
        "calendar_status" => "crate::tdbe::types::enums::CalendarStatus",
        other => panic!("unsupported tdbe struct field type '{other}' for {type_name}.{field}"),
    }
}
